def gen(rng, size):
    n = max(1, size)
    nums = []
    while len(nums) < n:
        base = rng.randint(1, 999000000)
        cluster = rng.randint(1, 50)
        for _ in range(cluster):
            if len(nums) >= n:
                break
            nums.append(base + rng.randint(-20, 20))
    k = rng.randint(0, 5000)
    return [nums, k]

