class Solution:
    def maxFrequencyScore(self, nums, k):
        srt = sorted(nums)
        n = len(srt)
        prefix = [0] * (n + 1)
        for i, v in enumerate(srt):
            prefix[i + 1] = prefix[i] + v

        def window_cost(l, r):
            m = (l + r) // 2
            median = srt[m]
            left_count = m - l
            left_sum = prefix[m] - prefix[l]
            right_count = r - m
            right_sum = prefix[r + 1] - prefix[m + 1]
            return (median * left_count - left_sum) + (right_sum - median * right_count)

        def feasible(length):
            for l in range(0, n - length + 1):
                if window_cost(l, l + length - 1) <= k:
                    return True
            return False

        lo, hi = 1, n
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if feasible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

