var maxFrequencyScore = function(nums, k) {
    const srt = nums.slice().sort((a, b) => a - b);
    const n = srt.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + srt[i];

    function windowCost(l, r) {
        const m = Math.floor((l + r) / 2);
        const median = srt[m];
        const leftCount = m - l;
        const leftSum = prefix[m] - prefix[l];
        const rightCount = r - m;
        const rightSum = prefix[r + 1] - prefix[m + 1];
        return (median * leftCount - leftSum) + (rightSum - median * rightCount);
    }

    let best = 1;
    let l = 0;
    for (let r = 0; r < n; r++) {
        while (windowCost(l, r) > k) l++;
        best = Math.max(best, r - l + 1);
    }
    return best;
};
